CREATE TABLE asset (id BIGSERIAL PRIMARY KEY, ticker VARCHAR(20) NOT NULL UNIQUE, description VARCHAR(150), asset_type VARCHAR(20) NOT NULL, segment VARCHAR(100), created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE portfolio (id BIGSERIAL PRIMARY KEY, name VARCHAR(100) NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE portfolio_asset (id BIGSERIAL PRIMARY KEY, portfolio_id BIGINT NOT NULL REFERENCES portfolio(id), asset_id BIGINT NOT NULL REFERENCES asset(id), quantity INTEGER NOT NULL, average_price NUMERIC(19,4), target_price NUMERIC(19,4), CONSTRAINT uk_portfolio_asset UNIQUE (portfolio_id, asset_id));
CREATE TABLE goal (id BIGSERIAL PRIMARY KEY, portfolio_asset_id BIGINT NOT NULL UNIQUE REFERENCES portfolio_asset(id), target_quantity INTEGER NOT NULL);
